solution_code:
#include <iostream>
#include <cassert>

int factorial(int n) {
    assert(n >= 0);
    if (n == 0) return 1;
    int result = 1;
    for (int i = 2; i <= n; ++i)
        result *= i;
    return result;
}

int main() {
    int n;
    std::cin >> n;
    std::cout << n << "! = " << factorial(n) << '\n';
    return 0;
}

