solution_code:
#include <iostream>
#include <cassert>

static_assert(sizeof(int) >= 4, "int too small");

int assertedClamp(int val, int lo, int hi) {
    assert(lo <= hi);
    if (val < lo) return lo;
    if (val > hi) return hi;
    return val;
}

int main() {
    int val, lo, hi;
    std::cin >> val >> lo >> hi;
    std::cout << assertedClamp(val, lo, hi) << '\n';
    return 0;
}
